#!/usr/bin/env node
/**
 * Generates a large realistic project fixture for typeship performance testing.
 * Produces ~10 slices × ~80 types = ~800+ published types across ~60 source files.
 */

import { mkdirSync, writeFileSync, rmSync, existsSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = join(__dirname, 'large-project');

// Only clean the generated src/ tree so the root directory (and any open shell
// sessions pointing to it) is never invalidated by deletion + recreation.
const SRC_ROOT = join(ROOT, 'src');
if (existsSync(SRC_ROOT)) rmSync(SRC_ROOT, { recursive: true });

// ─── helpers ────────────────────────────────────────────────────────────────

function write(relPath, content) {
  const abs = join(ROOT, relPath);
  mkdirSync(dirname(abs), { recursive: true });
  writeFileSync(abs, content, 'utf8');
}

const header = `// This file is part of the large-project performance fixture.\n// Generated by gen-large-project.mjs — do not edit manually.\n\n`;

function pub(text) { return `/** @publish */\n${text}`; }

function enumType(name, values) {
  const members = values.map(([k, v]) => `  ${k} = '${v}',`).join('\n');
  return pub(`export enum ${name} {\n${members}\n}\n`);
}

function iface(name, fields, generics = '') {
  const members = fields.map(([n, t]) => `  ${n}: ${t};`).join('\n');
  return pub(`export interface ${name}${generics} {\n${members}\n}\n`);
}

function typeAlias(name, rhs) {
  return pub(`export type ${name} = ${rhs};\n`);
}

// ─── shared ─────────────────────────────────────────────────────────────────

write('src/shared/pagination.ts', header + [
  typeAlias('SortOrder', `'asc' | 'desc'`),
  typeAlias('CursorToken', 'string'),
  iface('PageInfo', [['page','number'],['pageSize','number'],['total','number'],['totalPages','number'],['hasNext','boolean'],['hasPrev','boolean']]),
  iface('CursorPageInfo', [['cursor','CursorToken | null'],['hasNext','boolean'],['count','number']]),
  iface('SortField', [['field','string'],['order','SortOrder']]),
  iface('PaginationInput', [['page','number'],['pageSize','number'],['sort','SortField[]']]),
  iface('PaginatedResponse<T>', [['items','T[]'],['pageInfo','PageInfo'],['sort','SortField | null']], '<T>'),
  iface('CursorResponse<T>', [['edges','T[]'],['pageInfo','CursorPageInfo']], '<T>'),
].join('\n'));

write('src/shared/common.ts', header + [
  typeAlias('UUID', 'string'),
  typeAlias('ISODateString', 'string'),
  typeAlias('Currency', `'USD' | 'EUR' | 'GBP' | 'JPY' | 'CAD' | 'AUD' | 'CHF' | 'SEK' | 'NOK' | 'DKK'`),
  typeAlias('Locale', 'string'),
  typeAlias('Timezone', 'string'),
  typeAlias('JSONValue', 'string | number | boolean | null | JSONObject | JSONValue[]'),
  typeAlias('JSONObject', 'Record<string, JSONValue>'),
  iface('Money', [['amount','number'],['currency','Currency'],['formatted','string']]),
  iface('Address', [['line1','string'],['line2','string | null'],['city','string'],['state','string'],['postalCode','string'],['countryCode','string'],['isDefault','boolean']]),
  iface('PhoneNumber', [['countryCode','string'],['number','string'],['extension','string | null']]),
  iface('DateRange', [['from','ISODateString'],['to','ISODateString']]),
  iface('TimeRange', [['fromHour','number'],['fromMinute','number'],['toHour','number'],['toMinute','number']]),
  iface('GeoCoordinates', [['latitude','number'],['longitude','number'],['altitude','number | null']]),
  iface('ApiError', [['code','string'],['message','string'],['field','string | null'],['details','string[]']]),
  iface('ApiResponse<T>', [['data','T'],['success','boolean'],['errors','ApiError[]'],['requestId','string'],['timestamp','ISODateString']], '<T>'),
  iface('BulkOperationResult', [['succeeded','number'],['failed','number'],['errors','ApiError[]']]),
  iface('AuditEntry', [['actorId','UUID'],['action','string'],['resourceType','string'],['resourceId','UUID'],['diff','JSONObject'],['timestamp','ISODateString'],['ipAddress','string']]),
  iface('Webhook', [['id','UUID'],['url','string'],['secret','string'],['events','string[]'],['active','boolean'],['createdAt','ISODateString']]),
].join('\n'));

write('src/shared/media.ts', header + [
  enumType('MediaType', [['Image','image'],['Video','video'],['Document','document'],['Audio','audio'],['Archive','archive']]),
  enumType('ImageFormat', [['JPEG','jpeg'],['PNG','png'],['WebP','webp'],['GIF','gif'],['SVG','svg'],['AVIF','avif']]),
  iface('ImageVariant', [['width','number'],['height','number'],['url','string'],['format','ImageFormat'],['sizeBytes','number']]),
  iface('ImageDto', [['id','UUID'],['url','string'],['altText','string | null'],['width','number'],['height','number'],['format','ImageFormat'],['variants','ImageVariant[]'],['createdAt','ISODateString']], ''),
  iface('VideoDto', [['id','UUID'],['url','string'],['thumbnailUrl','string'],['durationSeconds','number'],['width','number'],['height','number'],['sizeBytes','number'],['mimeType','string']]),
  iface('DocumentDto', [['id','UUID'],['url','string'],['filename','string'],['mimeType','string'],['sizeBytes','number'],['pageCount','number | null']]),
  iface('MediaUploadUrlDto', [['uploadUrl','string'],['fields','Record<string,string>'],['expiresAt','ISODateString'],['maxSizeBytes','number']]),
  iface('MediaDto', [['id','UUID'],['type','MediaType'],['url','string'],['filename','string'],['mimeType','string'],['sizeBytes','number'],['metadata','JSONObject'],['createdAt','ISODateString']], ''),
].join('\n').replace(/interface ImageDto<>/g, 'interface ImageDto').replace(/interface MediaDto<>/g, 'interface MediaDto'));

write('src/shared/i18n.ts', header + [
  typeAlias('TranslationKey', 'string'),
  typeAlias('TranslationMap', 'Record<TranslationKey, string>'),
  iface('LocalizedString', [['defaultValue','string'],['translations','Record<Locale, string>']]),
  iface('TranslationDto', [['key','TranslationKey'],['locale','Locale'],['value','string'],['updatedAt','ISODateString']]),
  iface('LocaleConfig', [['code','Locale'],['name','string'],['nativeName','string'],['rtl','boolean'],['enabled','boolean']]),
].join('\n'));

// ─── slice factory ───────────────────────────────────────────────────────────

/**
 * Generates a full slice with many types.
 * @param {string} sliceName   directory name
 * @param {object} def         slice definition
 */
function generateSlice(sliceName, def) {
  for (const [fileName, content] of Object.entries(def)) {
    write(`src/${sliceName}/${fileName}`, header + content);
  }
}

